#include <stdio.h>
#include <stdlib.h>
int main() {
    int T; if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int m, n; scanf("%d %d", &m, &n);
        int **mat = (int**)malloc(m * sizeof(int*));
        for (int i = 0; i < m; ++i) {
            mat[i] = (int*)malloc(n * sizeof(int));
            for (int j = 0; j < n; ++j) scanf("%d", &mat[i][j]);
        }
        int target; scanf("%d", &target);
        int row = 0, col = n - 1;
        int found = 0;
        while (row < m && col >= 0) {
            int val = mat[row][col];
            if (val == target) { found = 1; break; }
            else if (val > target) col--;
            else row++;
        }
        printf(found ? "true\n" : "false\n");
        for (int i = 0; i < m; ++i) free(mat[i]);
        free(mat);
    }
    return 0;
}

