int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int T; if(!(cin >> T)) return 0;
    while (T--) {
        int m, n; cin >> m >> n;
        vector<vector<int>> mat(m, vector<int>(n));
        for (int i = 0; i < m; ++i)
            for (int j = 0; j < n; ++j)
                cin >> mat[i][j];
        int target; cin >> target;
        int row = 0, col = n - 1;
        bool found = false;
        while (row < m && col >= 0) {
            int val = mat[row][col];
            if (val == target) { found = true; break; }
            else if (val > target) --col;
            else ++row;
        }
        cout << (found ? "true" : "false") << '\n';
    }
    return 0;
}

