const fs = require('fs');
const tokens = fs.readFileSync(0, 'utf-8').trim().split(/\s+/);
let idx = 0;
if (tokens.length === 0) process.exit(0);
const T = Number(tokens[idx++]);
let results = [];
for (let t = 0; t < T; ++t) {
  const m = Number(tokens[idx++]);
  const n = Number(tokens[idx++]);
  const mat = Array.from({ length: m }, () => {
    const row = [];
    for (let j = 0; j < n; ++j) row.push(Number(tokens[idx++]));
    return row;
  });
  const target = Number(tokens[idx++]);
  let row = 0, col = n - 1;
  let found = false;
  while (row < m && col >= 0) {
    const val = mat[row][col];
    if (val === target) { found = true; break; }
    else if (val > target) col--;
    else row++;
  }
  results.push(found ? 'true' : 'false');
}
console.log(results.join('\n'));

